// Solution
#include <iostream>
#include <vector>
using namespace std;

class Solution {
public:
    int fibonacci(int n) {
        if (n == 0) return 0;
        else if (n < 0) return -1;
        else if (n > 47) return -1;
        else {
            vector<int> fib(n + 1);
            fib[0] = 0;
            fib[1] = 1;
            for (int i = 2; i <= n; i++) fib[i] = fib[i - 1] + fib[i - 2];
            return fib[n];
        }
    }
};

int main() {
    Solution solution;
    int n;
    cin >> n;
    cout << solution.fibonacci(n) << endl;
    return 0;
}

