// Solution
import sys

class Solution:
    def fibonacci(self, n: int) -> int:
        if n == 0:
            return 0
        elif n < 0:
            return -1
        elif n > 47:
            return -1
        else:
            fib = [0] * (n + 1)
            fib[1] = 1
            for i in range(2, n + 1):
                fib[i] = fib[i - 1] + fib[i - 2]
            return fib[n]
    def main(self):
        n = int(input())
        print(self.fibonacci(n))

if __name__ == '__main__':
    Solution().main()

